class Solution:
    def maxSubarrays(self, nums):
        n = len(nums)
        best_sum = None
        best_count = 0
        for mask in range(1 << (n - 1)):
            cuts = [i + 1 for i in range(n - 1) if (mask >> i) & 1]
            bounds = [0] + cuts + [n]
            total = 0
            count = len(bounds) - 1
            for b in range(count):
                seg = nums[bounds[b]:bounds[b + 1]]
                a = seg[0]
                for v in seg[1:]:
                    a &= v
                total += a
            if best_sum is None or total < best_sum or (total == best_sum and count > best_count):
                best_sum = total
                best_count = count
        return best_count

