var maxSubarrays = function(nums) {
    let count = 0;
    let cur = -1;
    for (const num of nums) {
        cur = (cur === -1) ? num : (cur & num);
        if (cur === 0) {
            count++;
            cur = -1;
        }
    }
    return count > 0 ? count : 1;
};
